import java.io.*;

public class CharacterStreamExample {
    public static void main(String[] args) {
        // Writing characters to a file
        System.out.println("=== Writing characters ===");
        String text = "Hello, World!\nJava is fun.\nCharacter streams handle text.";

        try (FileWriter fw = new FileWriter("text.txt")) {
            fw.write(text);
            System.out.println("Text written: " + text.length() + " characters");
        } catch (IOException e) {
            System.out.println("Error writing: " + e.getMessage());
        }

        // Reading characters from a file
        System.out.println("=== Reading characters ===");
        try (FileReader fr = new FileReader("text.txt")) {
            int charRead;
            System.out.print("Content: ");
            while ((charRead = fr.read()) != -1) {
                System.out.print((char) charRead);
            }
            System.out.println();
        } catch (IOException e) {
            System.out.println("Error reading: " + e.getMessage());
        }

        // Reading into a character array
        System.out.println("=== Reading into array ===");
        try (FileReader fr = new FileReader("text.txt")) {
            char[] buffer = new char[50];
            int charsRead = fr.read(buffer);
            System.out.println("Chars read: " + charsRead);
            System.out.print("Content: " + new String(buffer, 0, charsRead));
        } catch (IOException e) {
            System.out.println("Error reading: " + e.getMessage());
        }

        // Appending to a file
        System.out.println("=== Appending ===");
        try (FileWriter fw = new FileWriter("text.txt", true)) {  // true = append
            fw.write("\nThis line is appended!");
            System.out.println("Appended successfully!");
        } catch (IOException e) {
            System.out.println("Error appending: " + e.getMessage());
        }

        // Reading the final content
        System.out.println("=== Final content ===");
        try (FileReader fr = new FileReader("text.txt")) {
            char[] buffer = new char[200];
            int charsRead = fr.read(buffer);
            System.out.println(new String(buffer, 0, charsRead));
        } catch (IOException e) {
            System.out.println("Error reading: " + e.getMessage());
        }
    }
}

